INSERT INTO `products` VALUES (1,1,'Purple tree saree kota doria','Elevate your ethnic wardrobe with this stunning purple authentic Kota Doria saree. Woven with care in the traditional looms of Kaithoon, this saree features traditional motifs, beautifully complemented by a simple. Crafted using skilled and detailed with pure silver & gold zari, it offers the signature sheer, lightweight, and breathable texture that authentic Kota fabric is famous for. Graceful, easy to drape, and timeless—this saree is a perfect choice for summer festivities, elegant daytime events, or sophisticated office wear.',100000.00,5,'saare_2.jpeg',1,'2026-06-13 02:59:08',NULL,NULL,'purple','silver and more purple','simple',NULL,'skilled',NULL,'pure silver & gold zari',NULL,NULL,'proudly handcrafted in kaithoon kota raj. india','silky & zari gold(kota doria)',NULL,NULL,NULL,NULL,NULL,NULL),(2,1,'Bird design with tree saree kota doria','Elevate your ethnic wardrobe with this stunning cyan authentic Kota Doria saree. Woven with care in the traditional looms of Kaithoon, this saree features traditional motifs, beautifully complemented by a bird design with mix color. Crafted using skilled and detailed with pure silver & gold zari, it offers the signature sheer, lightweight, and breathable texture that authentic Kota fabric is famous for. Graceful, easy to drape, and timeless—this saree is a perfect choice for summer festivities, elegant daytime events, or sophisticated office wear.',50000.00,5,'saare_3.jpeg',NULL,'2026-06-13 02:59:08',NULL,NULL,'cyan','gold and mix of color','bird design with mix color',NULL,'skilled',NULL,'pure silver & gold zari',NULL,NULL,'proudly handcrafted in kaithoon kota raj. india','silky & zari gold(kota doria)',NULL,NULL,NULL,NULL,NULL,NULL),(3,1,'Parrot design saree kota','Elevate your ethnic wardrobe with this stunning cream authentic Kota Doria saree. Woven with care in the traditional looms of Kaithoon, this saree features traditional motifs, beautifully compleme